var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"정말 이래도 괜찮은 걸까?","JPN":"本当にこんなことをして大丈夫なのかな？","ENG":"You sure it'll be okay?","TWN":"這樣真的沒問題嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이제 와서 뭘 그래?","JPN":"今更何を言ってんだよ。","ENG":"We can't back out now!","TWN":"現在說這些幹嘛？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"우리 때문에 그 애가 잘못되기라도 하면…","JPN":"俺たちのせいであの子の身に何か起きたら……","ENG":"But if something happens to her because of us...","TWN":"萬一她因此怎麼樣的話…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"먼저들 와서 기다리고 있었구려.","JPN":"お待ちしておりました。","ENG":"I see you were waiting for me.","TWN":"你們先來這裡等在下嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"어엇… 아, 안녕? 왔구나?","JPN":"あっ……や、やあ？","ENG":"O-oh... H-hi. You're here.","TWN":"呃…喔，哈，哈囉？你來啦？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이제 가자.","JPN":"よし、行こう。","ENG":"Let's go, then.","TWN":"我們走吧。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"여기가 공포의 집이야. 아마도 침식체는… 여기서 나타날 거야.","JPN":"ここが恐怖の家だ。おそらく侵食体が現れるのは……ここだ。","ENG":"This is the haunted house. I think... the C.O.'s gonna be here.","TWN":"這裡跟鬼屋一樣…可能會有侵蝕體跑出來。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이, 이쪽엔 아무것도 없는 것 같은데… 좀 더 안쪽으로 들어가볼까?","JPN":"こ、ここには何もないみたいだぞ……もう少し奥に入ってみよう。","ENG":"Th-there's nothing over here... Should we go in deeper?","TWN":"這，這裡好像沒東西…要再往裡面一點嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"으앗! 바닥이…!","JPN":"うわっ！　床が……！","ENG":"Whoa! The floor...!","TWN":"啊！地板…！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"길이 낡았소. 조심하구려.","JPN":"かなり足元が脆いです。ご注意を。","ENG":"The path is dilapidated. Be careful.","TWN":"地板有點老舊，要小心。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"응… 잡아줘서 고마워.","JPN":"ああ……支えてくれてありがとうな。","ENG":"Yeah... Thanks for catching me.","TWN":"嗯…謝謝你抓住我。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"위험했네. 나무바닥이 다 삭았잖아.","JPN":"危なかったな。木の床が朽ちているみたいだぞ。","ENG":"That was close. The wooden floor has rotted all the way.","TWN":"好危險，木頭地板都腐蝕了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그래… 침식파가 거쳐간 건물은 빨리 낡는 경우도 있댔으니까. 내가 부주의했어.","JPN":"ああ……一度侵食波に襲われた建物は劣化が早くなることもあるって知ってたのに、不注意だった。","ENG":"Yeah... Places where the Corruption ray passed tend to age quicker. I should've been more careful.","TWN":"是啊…聽說被侵蝕波侵蝕過的建築物都會腐蝕得比較快，剛剛是我太不小心。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"지금부터는 본인이 앞장서리다.","JPN":"ここから先は自分が先頭に立って進むとしましょう。","ENG":"From this point, I shall take lead.","TWN":"換在下走前面吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그 친구. 아카데미에 오기 전엔 사람을 수도 없이 죽여본 살인마거든.</color>","JPN":"<color=#ff3636>あいつ。アカデミーに来る前は、数えきれないほどの人を殺してきた殺人鬼なんだぞ。</color>","ENG":"<color=#ff3636>That girl. She is a murderer who has taken countless lives before attending the Academy.</color>","TWN":"<color=#ff3636>她在來學院之前，是個殺人無數的殺人魔。</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그러니 찜찜한 마음이 들더라도, 죄책감 같은 건 갖지 않아도 돼.</color>","JPN":"<color=#ff3636>だから後ろめたいって思ったり、罪悪感なんて感じなくていい。</color>","ENG":"<color=#ff3636>So even if you feel uncomfortable about it, there is no need to feel guilty.</color>","TWN":"<color=#ff3636>所以就算心裡有點不安，也不需要感到愧疚。</color>"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"저기 말이야, 신입생.","JPN":"なぁ、新入生。","ENG":"Yo, new kid.","TWN":"新生，我問你。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"너… 정말로 사람을 죽여본 적 있어?","JPN":"お前……本当に人を殺したのか？","ENG":"Have you... ever killed anyone before?","TWN":"你…有殺過人嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"왜 그런 질문을 하는진 모르겠지만…","JPN":"どういう意図の質問かわかりかねますが……","ENG":"I do not understand why you ask this question...","TWN":"雖然不知道你為何這麼問…"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"부정하진 않으리다.","JPN":"否定はしません。","ENG":"But I will not deny the fact that I did.","TWN":"但在下不否認。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…그렇구나.","JPN":"……そうか。","ENG":"...Okay.","TWN":"…是嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"저기, 사실은 말이지.","JPN":"あの、実はな。","ENG":"Actually, the thing is...","TWN":"我告訴你吧，"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"우린 침식체 같은 걸 찾으려고 널 데려온 게 아니야.","JPN":"俺たちは侵食体なんかのために、お前をここに連れて来たんじゃないんだ。","ENG":"We didn't want you to tag along so we could find a C.O.","TWN":"我們把你帶來這裡，才不是因為要找什麼侵蝕體。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"알고 있다오.","JPN":"存じております。","ENG":"I am aware.","TWN":"在下知道。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"뭐…? 그걸 어떻게…","JPN":"なっ……？　どうやって……","ENG":"What? But how did you...","TWN":"什麼…？你怎麼會…"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"어, 어라? 이 소린?","JPN":"な、なんだ？　この音は？","ENG":"H-huh? What's that sound?","TWN":"呃呃？這個聲音是？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나가는 문이 닫혔어!","JPN":"出口を塞がれた！","ENG":"The door just closed!","TWN":"門被堵起來了！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"콜록 콜록… 가스라고?","JPN":"ゲホッ、ゲホッ……ガスか？","ENG":"*Cough* *Cough* Is this gas?","TWN":"咳咳咳咳…是瓦斯？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"잠깐만요! 우리도 아직 안에 있다고요!","JPN":"ちょっと待ってください！　俺たちはまだ中に！","ENG":"Wait! We're still in here!","TWN":"喂！我們還在裡面欸！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"으윽… 의식이…","JPN":"ううっ……意識が……","ENG":"Ngh... I can't...","TWN":"咳咳…意識…"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"드디어 잡았군.","JPN":"やっと捕らえられたな。","ENG":"I finally got you.","TWN":"終於抓到了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"실험체 인도를 시작한다.","JPN":"実験体の引渡しを開始する。","ENG":"Start transporting the test subject.","TWN":"開始引渡實驗體。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야, 그 녀석? 수업이 시작된 지가 언젠데 왜 안 와?","JPN":"あいつ、何してんの？　授業なのに、流石に遅れすぎじゃない？","ENG":"What's up with her again? Class has already started, but why isn't she back?","TWN":"那傢伙搞什麼？都開始上課了怎麼還沒看到人？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 별일이네. 땡땡이도 안 치고 다른 친구까지 걱정해 주다니.","JPN":"珍しいね。サボらなかっただけでも珍しいのに、他人の心配までするなんて。","ENG":"That's strange. You're not skipping class and you're worrying about someone other than you.","TWN":"你今天怎麼回事？沒有翹課就算了，還擔心別人？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"누가 걱정한대? 지난 모의전투가 영 찜찜해서 이번엔 제대로 이겨주려던 것뿐이라고.","JPN":"心配なんかしてないわよ！　前回の模擬戦闘が曖昧なまま終わったから、今度こそコテンパンにしてやろうと思っているだけ。","ENG":"Who said I was worried? I just want to beat her properly because something seemed off about our last simulation battle.","TWN":"誰擔心啦！只是因為上次的模擬戰贏得不夠痛快，這次我想要光明正大贏一場而已。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 이런 식으로 또 늦으면 담판을 못 짓게 되잖아!","JPN":"でもこうやって遅刻してたら、再勝負できなくなるじゃない！","ENG":"But I can't do that if she's late like this!","TWN":"她再不出現的話我要怎麼贏！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 그거.","JPN":"あ、そういえば。","ENG":"Oh, that?","TWN":"說到這個，"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너랑 시엘이 대결하던 날, 어디선가 날아온 탄환을 막으려다 시엘이 다친 거라던데. 범인은 잡았으려나?","JPN":"シエルちゃん、あなたと対決した日に、飛んできた銃弾を防ごうとして怪我したらしいんだけど、犯人は捕まったのかな？","ENG":"I heard that Ciel was hurt while blocking a stray bullet that flew toward you two during the battle. I wonder if they've caught the perp yet.","TWN":"你和希爾交手那天，不知道從哪飛出一顆子彈，結果希爾為了擋子彈受傷了。不知道犯人抓到沒？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐? 그게 무슨 말도 안 되는 소리야?","JPN":"え？　いったい何の話？","ENG":"What? Don't be ridiculous!","TWN":"蛤？你在說什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뜬금없이 누가 훈련 중에 총을 쐈는진 몰라도, 그 열등생 녀석이 탄환 같은 걸 쳐낼 수 있을 리…","JPN":"いったい誰が訓練中に銃を撃ったのか知らないけど、あんな劣等生に弾丸を弾き返せるわけが……","ENG":"I dunno who fired a gun in the middle of class, but there's no way that a loser like her could ever deflect a bull–","TWN":"雖然不知道是哪個傢伙突然在訓練中開槍，但劣等生怎麼可能擋下子彈…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…있네?","JPN":"……あるかも……？","ENG":"...I guess she can.","TWN":"…可能欸！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아차-","JPN":"あちゃ～","ENG":"Oops...","TWN":"哎呀～"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님이 시엘의 진-짜 친한 친구 아니면 아무한테도 말하지 말랬는데. 내 실수.","JPN":"生徒会長にシエルちゃんの本当の友達以外には言うなって口止めされてたのに。つい言っちゃった。","ENG":"Ms. President told me not to say anything to anyone unless that person was reaaally close with Ciel. My bad.","TWN":"學生會長特地吩咐，這件事只能告訴希爾真-正的朋友，我說漏嘴了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이건 우리만 알고 있는 비밀이다-?","JPN":"今のはここだけの内緒だからね～？","ENG":"So, keep this between us, okay?","TWN":"這是我們的秘密喔？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 너! 열등생이 아카데미에서 받은 휴대폰 번호, 알고 있지?","JPN":"ねえ、あんたってあの劣等生のアカデミー用携帯の番号、知ってるわよね？","ENG":"Hey, you! You know that loser's phone number, right?","TWN":"喂！學院不是有給劣等生手機嗎？你知道電話號碼吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 그렇긴 한데.","JPN":"うん？　知ってるけど。","ENG":"Hmm? I do.","TWN":"嗯？好像吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"알려줘. 역시 본인에게 직접 물어보는 게 좋겠어.","JPN":"教えなさい。その話、やっぱり私も本人に直接聞いてみたいわ。","ENG":"Spill it. I'm going to ask her myself.","TWN":"跟我說，我要直接問本人比較快。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"실험체를 데리고 온 나머지 둘은 어떻게 할까요?","JPN":"実験体以外のあと二人はどういたしましょうか？","ENG":"What should we do about the two who brought the test subject?","TWN":"跟著實驗體一起帶來的另外二個人要怎麼處理？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"목적엔 없었지만, 굳이 살려서 보내면 번거로워질 뿐이지.","JPN":"計画にはなかったが、わざわざ生きて帰らせるのも面倒を増やすだけだ。","ENG":"It's not part of our goal, but letting them go will only create more work later down the road.","TWN":"雖然不在計劃裡，但就這樣放走他們只怕會節外生枝。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"같이 처분해라.","JPN":"まとめて処分しろ。","ENG":"Terminate them.","TWN":"都處理掉吧。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Yes, sir.","TWN":"是！"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_HUMEN","text":{"KOREA":"…전화기 소리? 주머니에 있는 건가?","JPN":"……着信音？　ポケットか？","ENG":"...A phone's ringing? Is it in her pocket?","TWN":"…電話聲？在口袋裡嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_HUMEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"음?!","JPN":"むっ！？","ENG":"Huh?","TWN":"嗯？！"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"교우들에게 나를 데려오라 사주한 것이, 그대들이오?","JPN":"学友たちに、私をここに連れてこさせたのは、貴殿らでしょうか？","ENG":"Are you the one who ordered my classmates to lure me here?","TWN":"就是你們指使同學把在下帶到這裡來的嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"카운터에게도 확실히 먹힐 만큼 약을 썼을 텐데…","JPN":"カウンターでも確実に動けなくなるぐらいの薬を使ったはずが……","ENG":"I used enough sedatives to knock out a Counter...","TWN":"藥量應該足以讓制裁者昏過去才對…"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"왜 멀쩡한 거지?","JPN":"なぜ効いていない？","ENG":"How are you awake?","TWN":"你為何沒事？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인을 해할 수 있는 독은 없소.","JPN":"自分に毒は効きません。","ENG":"No poison can harm me.","TWN":"因為在下百毒不侵，"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런 간단한 이유요.","JPN":"単純明快ではありますが、それが答えです。","ENG":"It is as simple as that.","TWN":"如此而已。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"…이상할 정도로 침착하군. 처음부터 함정이란 걸 알고 있었던 거냐?","JPN":"……奇妙なぐらい落ち着いていやがる。最初から罠だと気づいていたのか？","ENG":"...You're oddly calm. Did you know this was a trap?","TWN":"…你異常冷靜呢，你一開始就知道這是個陷阱嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"교우들에게서 익숙한 냄새가 났다오.","JPN":"学友たちから馴染みのある匂いがしました。","ENG":"I could sense a familiar scent on him.","TWN":"因為同學身上有散發出熟悉的味道。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"엘릭서를 팔던 뒷골목 사내의 냄새. 그리고… 지금은 모습을 감추고 있는 그자의 냄새도.","JPN":"エリクサーを売っていた路地裏の男の匂い、そして……今は姿を眩ましたあの者の匂いです。","ENG":"The smell of the man who was selling the Elixir in the back alley. And... the smell of the man who is currently hiding his presence.","TWN":"賣聖水的暗巷的味道，還有…現在躲起來的那個人的味道。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"냄새 타령이야 그렇다 쳐도, C급 카운터가 이런 기습적인 총격을 막아내다니.","JPN":"匂い？　わけがわからないな。だが、それはともかく、C級カウンターが不意打ちの銃撃に対処するとは。","ENG":"This smell thing aside, it's impressive that a Grade C Counter like yourself can deflect a bullet.","TWN":"先不說味道，C級制裁者可以擋下突然射出的子彈。"},"stage":{"bg":"HALL","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"녀석이 말한 대로 쓸 만한 이레귤러로군.","JPN":"あいつの言う通り、かなり使えるイレギュラーのようだ。","ENG":"It's just like he told us. She's a useful Irregular.","TWN":"那傢伙說的沒錯，你確實是不錯的非典型實驗體。"},"stage":{"bg":"HALL","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"모두 저 녀석을 잡아라.","JPN":"全員、あいつを捕らえろ。","ENG":"Men, grab her!","TWN":"把她給我抓起來！"},"stage":{"bg":"HALL","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};